const {stages,templates}=window.NUDO_DATA;
const STORE='nudo_control_obra_v2';
const PHOTO_DB='nudo_control_photos_v2';
const FLOW=['Abierta','En proceso','Corregida','Verificada'];
const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const ico=n=>`<svg aria-hidden="true"><use href="#i-${n}"/></svg>`;
const esc=(v='')=>String(v).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));
const SB_CONFIG=window.NUDO_SUPABASE_CONFIG;
const sb=window.supabase.createClient(SB_CONFIG.url,SB_CONFIG.publishableKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}});
let state=load(), route={view:'home'}, visit=null, detail=null, calendarDate=new Date(), calendarSelected=null;
let authReady=false,currentSession=null,currentProfile=null,authMessage='',syncing=false,lastSync=null,workspaceError='',managementLoading=false;
function seed(){return{user:{id:'',name:'',role:'architect'},projects:[],checks:{},issues:[],visits:[],plannedVisits:[],activeVisit:null}}
function load(){try{const x=JSON.parse(localStorage.getItem(STORE));if(x&&typeof x==='object'){x.projects=x.projects||[];x.visits=x.visits||[];x.plannedVisits=x.plannedVisits||[];x.issues=x.issues||[];x.checks=x.checks||{};x.user=x.user||{id:'',name:'',role:'architect'};if(x.activeVisit&&x.activeVisit.filter==='pending')x.activeVisit.filter='all';return x}}catch(e){}return seed()}
function save(){localStorage.setItem(STORE,JSON.stringify(state))}
function project(id){return state.projects.find(p=>p.id===id)}
function stage(id){return stages.find(s=>s.id===id)}
function key(pid,sid,sector,iid){return [pid,sid,sector,iid].join('|')}
function getCheck(pid,sid,sector,iid){return state.checks[key(pid,sid,sector,iid)]||{status:'pending',note:'',updatedAt:null,contactId:null,dueDate:null,visitId:null}}
function setCheck(pid,sid,sector,iid,patch){state.checks[key(pid,sid,sector,iid)]={...getCheck(pid,sid,sector,iid),...patch,updatedAt:new Date().toISOString()};save()}
function fmt(v,time=false){if(!v)return'Sin chequeos';const d=new Date(v);return d.toLocaleDateString('es-UY',time?{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}:{day:'2-digit',month:'short',year:'numeric'})}
function statsProject(p){let total=0,reviewed=0,done=0,obs=0,bad=0,critical=0,last=null;for(const s of stages.filter(x=>p.enabledStages.includes(x.id)))for(const sec of p.sectors)for(const it of s.items){total++;const c=getCheck(p.id,s.id,sec,it.id);if(c.status!=='pending')reviewed++;if(c.status==='ok')done++;if(c.status==='obs')obs++;if(c.status==='bad')bad++;if(it.priority==='Crítica'&&c.status!=='ok')critical++;if(c.updatedAt&&(!last||c.updatedAt>last))last=c.updatedAt}return{total,reviewed,done,obs,bad,critical,last}}
function statsStage(p,s,sector=null){const secs=sector?[sector]:p.sectors;let total=0,reviewed=0,done=0,obs=0,bad=0,last=null;for(const sec of secs)for(const it of s.items){total++;const c=getCheck(p.id,s.id,sec,it.id);if(c.status!=='pending')reviewed++;if(c.status==='ok')done++;if(c.status==='obs')obs++;if(c.status==='bad')bad++;if(c.updatedAt&&(!last||c.updatedAt>last))last=c.updatedAt}return{total,reviewed,done,obs,bad,last}}
function openIssues(pid){return state.issues.filter(i=>i.projectId===pid&&i.lifecycle!=='Verificada')}
function toast(t){const x=$('#toast');x.textContent=t;x.classList.add('show');setTimeout(()=>x.classList.remove('show'),1700)}
function go(r){route=r;render();scrollTo(0,0)}
function nav(name){$$('#bottomNav button').forEach(b=>b.classList.toggle('active',b.dataset.nav===name))}
function render(){const a=$('#app'),top=$('.topbar'),bottom=$('#bottomNav');if(!authReady){top.style.display='none';bottom.style.display='none';a.innerHTML=loadingView();return}if(!currentSession){top.style.display='none';bottom.style.display='none';a.innerHTML=loginView();bindLogin();return}top.style.display='flex';bottom.style.display=route.view==='visit'?'none':'grid';nav(['project','visit','project-admin'].includes(route.view)?'projects':route.view);if(route.view==='home')a.innerHTML=home();if(route.view==='projects')a.innerHTML=projects();if(route.view==='project')a.innerHTML=projectView(project(route.projectId));if(route.view==='project-admin')a.innerHTML=projectAdminView(project(route.projectId));if(route.view==='visit')a.innerHTML=visitView();if(route.view==='search')a.innerHTML=searchView();if(route.view==='visits')a.innerHTML=visitsView();bind()}
function loadingView(){return`<section class="auth-shell"><div class="auth-card"><div class="auth-logo">JP</div><div class="auth-kicker">NUDO</div><h1>Conectando…</h1><p>Verificando la sesión y el acceso a las obras.</p></div></section>`}
function loginView(){return`<section class="auth-shell"><form class="auth-card" id="loginForm"><div class="auth-logo">JP</div><div class="auth-kicker">GESTOR DE OBRAS</div><h1>Iniciar sesión</h1><p>Acceso interno del estudio.</p>${authMessage?`<div class="auth-error">${esc(authMessage)}</div>`:''}<div class="field"><label>Correo</label><input id="loginEmail" type="email" autocomplete="email" required></div><div class="field"><label>Contraseña</label><input id="loginPassword" type="password" autocomplete="current-password" required></div><button class="solid auth-submit" id="loginButton" type="submit">Ingresar</button></form></section>`}
function bindLogin(){const form=$('#loginForm');if(!form)return;form.onsubmit=async e=>{e.preventDefault();const button=$('#loginButton');button.disabled=true;button.textContent='Ingresando…';authMessage='';const{error}=await sb.auth.signInWithPassword({email:$('#loginEmail').value.trim(),password:$('#loginPassword').value});if(error){authMessage=loginErrorText(error);button.disabled=false;render()}}}
function loginErrorText(error){const m=(error?.message||'').toLowerCase();if(m.includes('invalid login'))return'Correo o contraseña incorrectos.';if(m.includes('email not confirmed'))return'El correo todavía no fue confirmado.';return error?.message||'No se pudo iniciar sesión.'}
function home(){const ps=state.projects.filter(p=>p.status!=='Finalizado'),crit=state.issues.filter(i=>i.lifecycle!=='Verificada'&&(i.status==='bad'||i.priority==='Crítica')).slice(0,5),recent=[...state.visits].sort((a,b)=>b.startedAt.localeCompare(a.startedAt)).slice(0,4);return`<section class="hero"><div class="kicker">DIRECCIÓN DE OBRA</div><h1><strong>GESTOR DE OBRAS</strong></h1><p>actualización continua de estado de obras</p><div class="hero-actions"><button class="solid" data-action="new-project">${ico('plus')} Nuevo proyecto</button></div></section><section class="sync-banner ${workspaceError?'sync-error':''}"><span class="dot ${workspaceError?'red':'green'}"></span><div><b>${workspaceError?'No se pudo actualizar la base':'Datos actualizados'}</b><small>${workspaceError?esc(workspaceError):'Los proyectos están sincronizados. Las visitas y chequeos siguen guardándose en este dispositivo durante esta etapa.'}</small></div><button data-action="sync-now">${syncing?'Sincronizando…':'Actualizar'}</button></section>${state.activeVisit?activeVisit():''}<section class="section"><div class="section-head"><h2>Proyectos activos</h2><button data-action="all-projects">Ver todos</button></div><div class="list project-grid">${ps.map(projectRow).join('')||empty('No hay proyectos activos.')}</div></section><section class="section"><div class="section-head"><h2>Pendientes críticos</h2><button data-action="find-critical">Buscar</button></div><div class="list">${crit.map(issueRow).join('')||empty('No hay pendientes críticos abiertos.')}</div></section><section class="section"><div class="section-head"><h2>Visitas recientes</h2><button data-action="all-visits">Historial</button></div><div class="list">${recent.map(visitRow).join('')||empty('Todavía no hay visitas registradas.')}</div></section>`}
function activeVisit(){const v=state.activeVisit,p=project(v.projectId),s=stage(v.stageId);return`<section class="section"><button class="row" data-action="resume"><span class="dot yellow"></span><div class="row-main"><div class="row-title">Continuar visita</div><div class="row-sub">${esc(p.name)} · ${esc(s.name)} · ${esc(v.sector)}</div></div>${ico('next')}</button></section>`}
function projectRow(p){const st=statsProject(p),s=stage(p.currentStage);return`<button class="row" data-project="${p.id}"><div class="count-badge"><b>${st.reviewed}</b><span>/${st.total}</span></div><div class="row-main"><div class="row-title">${esc(p.name)}</div><div class="row-sub">${esc(p.status)} · ${esc(s?.name||'Sin etapa')}</div><div class="row-meta"><span class="urgent">${st.critical} críticos</span><span class="warning">${st.obs} observaciones</span><span>${projectRoleLabel(p.projectRole)}</span></div></div>${ico('next')}</button>`}
function issueRow(i){const p=project(i.projectId);return`<button class="row" data-issue="${i.id}"><span class="dot ${i.status==='bad'?'red':'yellow'}"></span><div class="row-main"><div class="row-title">${esc(i.code)} · ${esc(i.title)}</div><div class="row-sub">${esc(p?.name||'')} · ${esc(i.sector)} · ${esc(i.lifecycle)}</div><div class="row-meta"><span>${esc(i.contactName||'Sin responsable')}</span><span>${i.dueDate?'Vence '+fmt(i.dueDate):'Sin fecha'}</span></div></div>${ico('next')}</button>`}
function visitRow(v){const p=project(v.projectId),s=stage(v.stageId);return`<button class="row" data-visit="${v.id}"><span class="dot green"></span><div class="row-main"><div class="row-title">${esc(p?.name||'Proyecto')} · ${esc(s?.name||'Etapa')}</div><div class="row-sub">${esc(v.sector)} · ${fmt(v.startedAt,true)}</div><div class="row-meta"><span>${ico('user')} ${esc(v.userName||state.user.name)}</span><span>${v.reviewed||0} revisados</span><span>${v.issues||0} observaciones</span></div></div>${ico('next')}</button>`}
function empty(t){return`<div class="empty">${esc(t)}</div>`}
function projects(){return`<div class="page-head"><div><h1>Proyectos</h1><p>${state.projects.length} proyectos registrados</p></div></div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="projectSearch" placeholder="Buscar proyecto, cliente o ubicación"></div></div><div class="list project-grid" id="projectList">${state.projects.map(projectRow).join('')}</div><button class="floating" data-action="new-project">${ico('plus')}</button>`}
function projectView(p){if(!p)return empty('Proyecto no encontrado.');const st=statsProject(p),current=stage(p.currentStage),issues=openIssues(p.id),canManage=['owner','admin'].includes(p.projectRole);return`<div class="page-head"><button class="back" data-action="back-projects">${ico('back')}</button><div><h1>${esc(p.name)}</h1><p>${esc(p.template)} · ${esc(p.status)}</p></div></div><section class="summary"><div class="summary-top"><div><h2>${esc(p.name)}</h2><p>Etapa actual: ${esc(current?.name||'Sin definir')} · Último chequeo: ${fmt(st.last,true)}</p></div>${canManage?`<button class="icon-btn" data-action="manage-project" aria-label="Administrar proyecto">${ico('settings')}</button>`:''}</div><div class="metrics"><div class="metric"><b>${st.reviewed}/${st.total}</b><span>Chequeados</span></div><div class="metric"><b>${st.critical}</b><span>Críticos</span></div><div class="metric"><b>${issues.length}</b><span>Abiertos</span></div></div><div class="hero-actions"><button class="solid" data-action="start-visit">${ico('plus')} Comenzar visita</button><button class="ghost" data-action="project-issues">${ico('alert')} Observaciones</button></div>${canManage?`<button class="management-link" data-action="manage-project">Administrar datos, arquitectos y accesos ${ico('next')}</button>`:''}</section><section class="section"><div class="section-head"><h2>Etapas habilitadas</h2><button data-action="edit-stages">Configurar</button></div><div class="list">${stages.map((s,n)=>stageRow(p,s,n)).join('')}</div></section>`}
function stageRow(p,s,n){const enabled=p.enabledStages.includes(s.id),st=statsStage(p,s);return`<button class="row ${enabled?'':'disabled'}" data-stage="${s.id}" ${enabled?'':'disabled'}><div class="stage-no">${String(n+1).padStart(2,'0')}</div><div class="row-main"><div class="row-title">${esc(s.name)}</div><div class="row-sub">${st.reviewed}/${st.total} chequeados · ${fmt(st.last,true)}</div></div><div class="stage-right"><b>${st.reviewed}/${st.total}</b><small>${st.bad} no conformes</small></div>${ico('next')}</button>`}
function projectRoleLabel(role){return({owner:'Propietario',admin:'Administrador',architect:'Arquitecto',read_only:'Solo lectura'})[role]||'Miembro'}
function projectAdminView(p){if(!p)return empty('Proyecto no encontrado.');if(!['owner','admin'].includes(p.projectRole))return`<div class="page-head"><button class="back" data-action="back-project">${ico('back')}</button><div><h1>Administración</h1><p>Sin permisos de administración</p></div></div>${empty('Solo el propietario o un administrador del proyecto puede modificar integrantes y eliminar la obra.')}`;const members=p.members||[];return`<div class="page-head"><button class="back" data-action="back-project">${ico('back')}</button><div><h1>Administrar proyecto</h1><p>${esc(p.name)}</p></div></div><section class="admin-card"><div class="section-head"><h2>Datos principales</h2></div><div class="field"><label>Nombre del proyecto</label><input id="adminName" value="${esc(p.name)}"></div><div class="inline"><div class="field"><label>Cliente</label><input id="adminClient" value="${esc(p.client||'')}"></div><div class="field"><label>Ubicación</label><input id="adminLocation" value="${esc(p.location||'')}"></div></div><div class="inline"><div class="field"><label>Estado</label><select id="adminStatus">${['No iniciado','En ejecución','Detenido','Próximo a entrega','Finalizado'].map(x=>`<option ${x===p.status?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Etapa actual</label><select id="adminStage">${p.enabledStages.map(id=>`<option value="${id}" ${id===p.currentStage?'selected':''}>${esc(stage(id)?.name||id)}</option>`).join('')}</select></div></div><div class="field"><label>Sectores — uno por línea</label><textarea id="adminSectors">${esc(p.sectors.join('\n'))}</textarea></div><div class="field"><label>Contactos de obra — uno por línea</label><textarea id="adminContacts">${esc(p.contacts.map(c=>c.name).join('\n'))}</textarea></div><button class="solid full-button" data-action="save-project-admin">Guardar datos del proyecto</button></section><section class="section admin-card"><div class="section-head"><h2>Arquitectos y accesos</h2><button data-action="reload-members">Actualizar</button></div><div class="member-list">${managementLoading?'<div class="empty">Cargando integrantes…</div>':members.map(m=>memberRow(p,m)).join('')||empty('No se pudieron cargar los integrantes.')}</div><div class="member-add"><div class="field"><label>Correo del arquitecto</label><input id="memberEmail" type="email" placeholder="arquitecto@estudio.com"></div><div class="field"><label>Permiso</label><select id="memberRole"><option value="architect">Arquitecto</option><option value="read_only">Solo lectura</option><option value="admin">Administrador</option></select></div><button class="ghost full-button" data-action="add-project-member">${ico('plus')} Agregar usuario existente</button><p class="muted">El correo debe corresponder a un usuario ya creado en Authentication → Users. La invitación automática requiere una función de servidor y se incorporará después.</p></div></section><section class="section danger-zone"><h2>Zona de riesgo</h2><p>Eliminar el proyecto borra sus datos remotos relacionados. Esta acción no se puede deshacer.</p><button class="danger full-button" data-action="delete-project-admin">Eliminar proyecto</button></section>`}
function memberRow(p,m){const self=m.user_id===currentSession.user.id,owner=m.member_role==='owner';return`<article class="member-row"><div class="member-avatar">${esc((m.full_name||m.email||'?').trim().charAt(0).toUpperCase())}</div><div class="row-main"><div class="row-title">${esc(m.full_name||m.email||'Usuario')}</div><div class="row-sub">${esc(m.email||'')} · ${projectRoleLabel(m.member_role)}</div></div>${owner?'<span class="pill green">Propietario</span>':self?'<span class="pill">Vos</span>':`<button class="tiny" data-member-menu="${m.user_id}">${ico('dots')}</button>`}</article>`}
async function openProjectAdmin(p){if(!p||!['owner','admin'].includes(p.projectRole))return toast('No tenés permisos para administrar este proyecto');route={view:'project-admin',projectId:p.id};managementLoading=true;render();try{await loadProjectMembers(p)}catch(error){workspaceError=dbErrorText(error);toast(workspaceError)}finally{managementLoading=false;render()}}
async function loadProjectMembers(p){const{data,error}=await sb.rpc('list_project_members',{p_project_id:p.id});if(error)throw error;p.members=data||[];save()}
async function saveProjectAdmin(p){const button=$('[data-action="save-project-admin"]'),name=$('#adminName').value.trim(),client=$('#adminClient').value.trim(),location=$('#adminLocation').value.trim(),status=$('#adminStatus').value,current_stage=$('#adminStage').value,sectors=$('#adminSectors').value.split('\n').map(x=>x.trim()).filter(Boolean),contactNames=$('#adminContacts').value.split('\n').map(x=>x.trim()).filter(Boolean);if(!name)return toast('El proyecto necesita un nombre');button.disabled=true;button.textContent='Guardando…';try{const{error}=await sb.from('projects').update({name,client,location,status,current_stage,updated_at:new Date().toISOString()}).eq('id',p.id);if(error)throw error;await syncProjectSectors(p,sectors.length?sectors:['General']);await syncProjectContacts(p,contactNames);await loadRemoteWorkspace();route={view:'project-admin',projectId:p.id};await loadProjectMembers(project(p.id));render();toast('Proyecto actualizado')}catch(error){button.disabled=false;button.textContent='Guardar datos del proyecto';toast(dbErrorText(error))}}
async function addProjectMember(p){const email=$('#memberEmail').value.trim().toLowerCase(),role=$('#memberRole').value;if(!email)return toast('Ingresá el correo del arquitecto');const button=$('[data-action="add-project-member"]');button.disabled=true;button.textContent='Agregando…';try{const{error}=await sb.rpc('add_project_member_by_email',{p_project_id:p.id,p_email:email,p_member_role:role});if(error)throw error;await loadProjectMembers(p);render();toast('Arquitecto agregado')}catch(error){button.disabled=false;button.textContent='Agregar usuario existente';toast(dbErrorText(error))}}
function memberMenu(p,userId){const m=(p.members||[]).find(x=>x.user_id===userId);if(!m)return;modal('Acceso al proyecto',`<div class="field"><label>Integrante</label><input value="${esc(m.full_name||m.email)}" disabled></div><div class="field"><label>Permiso</label><select id="editMemberRole"><option value="architect" ${m.member_role==='architect'?'selected':''}>Arquitecto</option><option value="read_only" ${m.member_role==='read_only'?'selected':''}>Solo lectura</option><option value="admin" ${m.member_role==='admin'?'selected':''}>Administrador</option></select></div>`,`<button class="danger" id="removeMember">Quitar</button><button class="ghost" data-close>Cancelar</button><button class="solid" id="saveMemberRole">Guardar</button>`);$('#saveMemberRole').onclick=async()=>{const{error}=await sb.rpc('set_project_member_role',{p_project_id:p.id,p_user_id:userId,p_member_role:$('#editMemberRole').value});if(error)return toast(dbErrorText(error));await loadProjectMembers(p);closeModal();render();toast('Permiso actualizado')};$('#removeMember').onclick=async()=>{if(!confirm(`¿Quitar a ${m.full_name||m.email} del proyecto?`))return;const{error}=await sb.rpc('remove_project_member',{p_project_id:p.id,p_user_id:userId});if(error)return toast(dbErrorText(error));await loadProjectMembers(p);closeModal();render();toast('Integrante eliminado')}}
async function deleteManagedProject(p){if(!confirm(`¿Eliminar definitivamente ${p.name}?`))return;const{error}=await sb.from('projects').delete().eq('id',p.id);if(error)return toast(dbErrorText(error));await loadRemoteWorkspace();go({view:'projects'});toast('Proyecto eliminado')}

function searchView(){return`<div class="page-head"><div><h1>Buscar</h1><p>Proyectos, controles, observaciones y responsables</p></div></div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="globalSearch" autofocus placeholder="Ej.: impermeabilización, OBS-004, sanitario"></div></div><div id="searchResults" class="list">${empty('Ingresá un término de búsqueda.')}</div>`}
function visitsView(){const vs=[...state.visits].sort((a,b)=>b.startedAt.localeCompare(a.startedAt)),planned=[...state.plannedVisits].filter(x=>x.status!=='cancelled').sort((a,b)=>plannedStamp(a).localeCompare(plannedStamp(b))),monthLabel=calendarDate.toLocaleDateString('es-UY',{month:'long',year:'numeric'});return`<div class="page-head"><div><h1>Visitas</h1><p>Calendario, próximas inspecciones e historial del estudio</p></div><button class="icon-btn" data-action="schedule-visit">${ico('plus')}</button></div><section class="calendar-card"><div class="calendar-head"><button class="icon-btn" data-action="cal-prev">${ico('back')}</button><div><b>${monthLabel.charAt(0).toUpperCase()+monthLabel.slice(1)}</b><button data-action="cal-today">Hoy</button></div><button class="icon-btn" data-action="cal-next">${ico('next')}</button></div>${calendarGrid()}</section><section class="section"><div class="section-head"><h2>${calendarSelected?'Agenda del '+fmtDay(calendarSelected):'Próximas visitas tentativas'}</h2><button data-action="schedule-visit">Programar</button></div><div class="list" id="plannedList">${plannedRows(planned)}</div></section><section class="section"><div class="section-head"><h2>Visitas realizadas</h2></div><div class="list">${vs.map(visitRow).join('')||empty('Todavía no hay visitas registradas.')}</div></section>`}

function dateKey(d){const y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return`${y}-${m}-${day}`}
function fmtDay(v){if(!v)return'';return new Date(v+'T12:00:00').toLocaleDateString('es-UY',{day:'2-digit',month:'long'})}
function plannedStamp(v){return`${v.date||'9999-12-31'}T${v.time||'23:59'}`}
function plannedStatus(v){if(v.status==='completed')return'completed';const now=new Date(),d=new Date(`${v.date}T${v.time||'12:00'}:00`);return d<now?'overdue':'planned'}
function monthEvents(){const y=calendarDate.getFullYear(),m=calendarDate.getMonth();return{done:state.visits.filter(v=>{const d=new Date(v.startedAt);return d.getFullYear()===y&&d.getMonth()===m}),planned:state.plannedVisits.filter(v=>{if(v.status==='cancelled')return false;const d=new Date((v.date||'')+'T12:00:00');return d.getFullYear()===y&&d.getMonth()===m})}}
function calendarGrid(){const y=calendarDate.getFullYear(),m=calendarDate.getMonth(),first=new Date(y,m,1),last=new Date(y,m+1,0),offset=(first.getDay()+6)%7,{done,planned}=monthEvents(),today=dateKey(new Date());let cells='';for(let i=0;i<offset;i++)cells+='<div class="calendar-day empty-day"></div>';for(let day=1;day<=last.getDate();day++){const d=new Date(y,m,day),key=dateKey(d),hasDone=done.some(v=>dateKey(new Date(v.startedAt))===key),plans=planned.filter(v=>v.date===key),hasPlanned=plans.some(v=>plannedStatus(v)==='planned'),hasOverdue=plans.some(v=>plannedStatus(v)==='overdue');cells+=`<button class="calendar-day ${key===today?'today':''} ${key===calendarSelected?'selected':''}" data-day="${key}"><span>${day}</span><i>${hasDone?'<b class="event-dot done"></b>':''}${hasPlanned?'<b class="event-dot planned"></b>':''}${hasOverdue?'<b class="event-dot overdue"></b>':''}</i></button>`}return`<div class="calendar-week"><span>L</span><span>M</span><span>M</span><span>J</span><span>V</span><span>S</span><span>D</span></div><div class="calendar-grid">${cells}</div><div class="calendar-legend"><span><i class="event-dot done"></i> Realizada</span><span><i class="event-dot planned"></i> Tentativa</span><span><i class="event-dot overdue"></i> Atrasada</span></div>`}
function plannedRows(list){let filtered=list;if(calendarSelected){const completed=state.visits.filter(v=>dateKey(new Date(v.startedAt))===calendarSelected);const scheduled=list.filter(v=>v.date===calendarSelected);return[...scheduled.map(plannedVisitRow),...completed.map(visitRow)].join('')||empty('No hay visitas para esta fecha.')}filtered=list.filter(v=>plannedStatus(v)!=='overdue').slice(0,8);const overdue=list.filter(v=>plannedStatus(v)==='overdue');return[...overdue.map(plannedVisitRow),...filtered.map(plannedVisitRow)].join('')||empty('No hay próximas visitas tentativas.')}
function plannedVisitRow(v){const p=project(v.projectId),s=stage(v.stageId),status=plannedStatus(v),label=status==='overdue'?'Atrasada':'Tentativa';return`<button class="row planned-row" data-planned="${v.id}"><span class="dot ${status==='overdue'?'red':'yellow'}"></span><div class="row-main"><div class="row-title">${esc(p?.name||'Proyecto')} · ${esc(s?.name||'Etapa por definir')}</div><div class="row-sub">${fmtDay(v.date)}${v.time?' · '+esc(v.time):''} · ${esc(v.sector||'Sector por definir')}</div><div class="row-meta"><span>${ico('user')} ${esc(v.assignee||state.user.name)}</span><span class="${status==='overdue'?'urgent':'warning'}">${label}</span></div></div>${ico('next')}</button>`}
function scheduleVisit(existing=null){const projectsOptions=state.projects.filter(p=>p.status!=='Finalizado').map(p=>`<option value="${p.id}" ${p.id===(existing?.projectId||'')?'selected':''}>${esc(p.name)}</option>`).join('');if(!projectsOptions)return toast('Primero creá un proyecto');const initialProject=project(existing?.projectId)||state.projects.find(p=>p.status!=='Finalizado');modal(existing?'Editar visita tentativa':'Programar visita tentativa',`<div class="field"><label>Proyecto</label><select id="svProject">${projectsOptions}</select></div><div class="inline"><div class="field"><label>Fecha tentativa</label><input id="svDate" type="date" value="${esc(existing?.date||calendarSelected||dateKey(new Date()))}"></div><div class="field"><label>Hora</label><input id="svTime" type="time" value="${esc(existing?.time||'09:00')}"></div></div><div class="field"><label>Etapa prevista</label><select id="svStage"></select></div><div class="field"><label>Sector previsto</label><select id="svSector"></select></div><div class="field"><label>Arquitecto responsable</label><input id="svAssignee" value="${esc(existing?.assignee||state.user.name)}"></div><div class="field"><label>Objetivo / controles previstos</label><textarea id="svNote" placeholder="Ej.: liberar armaduras antes del hormigonado">${esc(existing?.note||'')}</textarea></div>`,`<button class="ghost" data-close>Cancelar</button>${existing?'<button class="danger" id="deleteScheduled">Eliminar</button>':''}<button class="solid" id="saveScheduled">${existing?'Guardar':'Programar'}</button>`);const fill=()=>{const p=project($('#svProject').value)||initialProject;$('#svStage').innerHTML=p.enabledStages.map(id=>`<option value="${id}" ${id===(existing?.stageId||p.currentStage)?'selected':''}>${esc(stage(id).name)}</option>`).join('');$('#svSector').innerHTML=p.sectors.map(x=>`<option ${x===(existing?.sector||p.sectors[0])?'selected':''}>${esc(x)}</option>`).join('')};$('#svProject').onchange=fill;fill();$('#saveScheduled').onclick=()=>{const payload={id:existing?.id||crypto.randomUUID(),projectId:$('#svProject').value,date:$('#svDate').value,time:$('#svTime').value,stageId:$('#svStage').value,sector:$('#svSector').value,assignee:$('#svAssignee').value.trim()||state.user.name,note:$('#svNote').value.trim(),status:'planned',createdAt:existing?.createdAt||new Date().toISOString(),updatedAt:new Date().toISOString()};if(!payload.date)return toast('Definí una fecha tentativa');const n=state.plannedVisits.findIndex(x=>x.id===payload.id);if(n>=0)state.plannedVisits[n]=payload;else state.plannedVisits.push(payload);save();closeModal();render();toast(existing?'Visita actualizada':'Visita programada')};if(existing)$('#deleteScheduled').onclick=()=>{if(!confirm('¿Eliminar esta visita tentativa?'))return;state.plannedVisits=state.plannedVisits.filter(x=>x.id!==existing.id);save();closeModal();render();toast('Visita eliminada')}}
function plannedVisitModal(id){const v=state.plannedVisits.find(x=>x.id===id);if(!v)return;const p=project(v.projectId),s=stage(v.stageId);modal('Visita tentativa',`<div class="check-meta"><span class="pill ${plannedStatus(v)==='overdue'?'red':'yellow'}">${plannedStatus(v)==='overdue'?'Atrasada':'Tentativa'}</span></div><p style="line-height:1.5"><b>${esc(p?.name||'Proyecto')}</b><br>${fmtDay(v.date)}${v.time?' · '+esc(v.time):''}<br>${esc(s?.name||'Etapa')} · ${esc(v.sector||'Sector')}</p><div class="field"><label>Responsable</label><input value="${esc(v.assignee||state.user.name)}" disabled></div>${v.note?`<div class="future"><b>Objetivo previsto</b><br>${esc(v.note)}</div>`:''}`,`<button class="ghost" data-close>Cerrar</button><button class="ghost" id="editScheduled">Editar</button><button class="solid" id="startScheduled">Comenzar visita</button>`);$('#editScheduled').onclick=()=>{closeModal();scheduleVisit(v)};$('#startScheduled').onclick=()=>{visit={id:crypto.randomUUID(),projectId:v.projectId,stageId:v.stageId,sector:v.sector,startedAt:new Date().toISOString(),filter:'all',query:'',userName:v.assignee||state.user.name,plannedVisitId:v.id};v.status='started';state.activeVisit=visit;save();closeModal();go({view:'visit'})}}

function visitView(){const v=visit||state.activeVisit;if(!v)return'';const p=project(v.projectId),s=stage(v.stageId),st=statsStage(p,s,v.sector),filter=v.filter||'all',q=(v.query||'').toLowerCase();let list=s.items.filter(it=>{const c=getCheck(p.id,s.id,v.sector,it.id);if(filter==='pending'&&c.status!=='pending')return false;if(filter==='critical'&&it.priority!=='Crítica')return false;if(filter==='issues'&&!['obs','bad'].includes(c.status))return false;return!q||it.task.toLowerCase().includes(q)||it.future.toLowerCase().includes(q)});return`<div class="visit-head"><div class="page-head"><button class="back" data-action="leave-visit">${ico('back')}</button><div><h1>${esc(s.name)}</h1><p>${esc(p.name)} · ${esc(v.sector)}</p></div></div><div class="visit-context">Visita iniciada ${fmt(v.startedAt,true)} · ${esc(v.userName||state.user.name)}</div><div class="progress-count"><b>${st.reviewed}/${st.total}</b><span>ítems chequeados</span></div></div><div class="toolbar"><div class="searchbox">${ico('search')}<input id="checkSearch" value="${esc(v.query||'')}" placeholder="Buscar control"></div><button class="filter-btn">${ico('filter')}</button></div><div class="tabs">${tab('all','Todos',filter)}${tab('pending','Sin revisar',filter)}${tab('critical','Críticos',filter)}${tab('issues','Observaciones',filter)}</div><div class="check-list">${list.map(it=>checkRow(p,s,v,it)).join('')||empty('No hay controles con este filtro.')}</div><div class="visit-bottom-actions no-print"><button class="ghost" data-action="save-return">${ico('back')} Guardar y volver</button><button class="solid" data-action="export-pdf">${ico('file')} Exportar PDF</button></div>`}
function tab(id,label,current){return`<button class="tab ${id===current?'active':''}" data-filter="${id}">${label}</button>`}
function checkRow(p,s,v,it){const c=getCheck(p.id,s.id,v.sector,it.id),statusClass=`status-${c.status}`;return`<article class="check ${statusClass} ${it.priority==='Crítica'?'critical':''}"><button class="checkmark ${c.status==='ok'?'done':''}" data-action="quick-ok" data-item="${it.id}">${c.status==='ok'?ico('check'):''}</button><button class="check-content" data-action="open-check" data-item="${it.id}"><div class="check-title">${esc(it.task)}</div><div class="check-meta">${it.priority==='Crítica'?'<span class="pill red">Crítico</span>':''}${it.blocks?'<span class="pill">Bloquea avance</span>':''}${c.status==='pending'?'<span class="pill">Sin revisar</span>':''}${c.status==='ok'?'<span class="pill green">Conforme</span>':''}${c.status==='obs'?'<span class="pill yellow">Observación</span>':''}${c.status==='bad'?'<span class="pill red">No conforme</span>':''}${c.updatedAt?`<span class="pill">${fmt(c.updatedAt,true)}</span>`:''}</div></button><button class="tiny" data-action="open-check" data-item="${it.id}">${ico('next')}</button></article>`}
function bind(){$$('[data-project]').forEach(b=>b.onclick=()=>go({view:'project',projectId:b.dataset.project}));$$('[data-stage]').forEach(b=>b.onclick=()=>newVisit(route.projectId,b.dataset.stage));$$('[data-issue]').forEach(b=>b.onclick=()=>issueModal(b.dataset.issue));$$('[data-visit]').forEach(b=>b.onclick=()=>reportModal(b.dataset.visit));$$('[data-planned]').forEach(b=>b.onclick=()=>plannedVisitModal(b.dataset.planned));$$('[data-day]').forEach(b=>b.onclick=()=>{calendarSelected=calendarSelected===b.dataset.day?null:b.dataset.day;render()});$$('[data-filter]').forEach(b=>b.onclick=()=>{const v=visit||state.activeVisit;v.filter=b.dataset.filter;persist(v);render()});$$('[data-member-menu]').forEach(b=>b.onclick=()=>memberMenu(project(route.projectId),b.dataset.memberMenu));$$('[data-action]').forEach(b=>b.onclick=()=>action(b.dataset.action,b));const ps=$('#projectSearch');if(ps)ps.oninput=()=>$$('#projectList .row').forEach(r=>r.hidden=!r.innerText.toLowerCase().includes(ps.value.toLowerCase()));const gs=$('#globalSearch');if(gs)gs.oninput=()=>search(gs.value);const cs=$('#checkSearch');if(cs)cs.oninput=()=>{const v=visit||state.activeVisit;v.query=cs.value;persist(v);render()}}
function action(a,e){const p=project(route.projectId);if(a==='new-project')newProject();if(a==='all-projects'||a==='back-projects')go({view:'projects'});if(a==='back-project')go({view:'project',projectId:route.projectId});if(a==='all-visits')go({view:'visits'});if(a==='find-critical'){go({view:'search'});setTimeout(()=>{$('#globalSearch').value='OBS';search('OBS')},0)}if(a==='resume'){visit=state.activeVisit;go({view:'visit'})}if(a==='start-visit')newVisit(route.projectId);if(a==='project-menu'||a==='manage-project')openProjectAdmin(p);if(a==='save-project-admin')saveProjectAdmin(p);if(a==='add-project-member')addProjectMember(p);if(a==='reload-members'){managementLoading=true;render();loadProjectMembers(p).then(()=>toast('Integrantes actualizados')).catch(error=>toast(dbErrorText(error))).finally(()=>{managementLoading=false;render()})}if(a==='delete-project-admin')deleteManagedProject(p);if(a==='edit-stages')stageConfig(p);if(a==='project-issues')issuesModal(route.projectId);if(a==='quick-ok')quickOk(e.dataset.item);if(a==='open-check')checkModal(e.dataset.item);if(a==='leave-visit')leaveVisit();if(a==='finish-visit'||a==='save-return')saveAndReturn();if(a==='export-pdf')exportVisitPdf();if(a==='schedule-visit')scheduleVisit();if(a==='sync-now')refreshRemote();if(a==='cal-prev'){calendarDate=new Date(calendarDate.getFullYear(),calendarDate.getMonth()-1,1);calendarSelected=null;render()}if(a==='cal-next'){calendarDate=new Date(calendarDate.getFullYear(),calendarDate.getMonth()+1,1);calendarSelected=null;render()}if(a==='cal-today'){calendarDate=new Date();calendarSelected=dateKey(new Date());render()}}
function newVisit(pid,sid=null){const p=project(pid);modal('Nueva visita',`<div class="field"><label>Etapa</label><select id="vStage">${p.enabledStages.map(id=>`<option value="${id}" ${id===(sid||p.currentStage)?'selected':''}>${esc(stage(id).name)}</option>`).join('')}</select></div><div class="field"><label>Sector</label><select id="vSector">${p.sectors.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>Realizada por</label><input id="vUser" value="${esc(state.user.name)}"></div><div class="muted">La fecha y hora se registran automáticamente.</div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="beginVisit">Comenzar inspección</button>`);$('#beginVisit').onclick=()=>{visit={id:crypto.randomUUID(),projectId:p.id,stageId:$('#vStage').value,sector:$('#vSector').value,startedAt:new Date().toISOString(),filter:'all',query:'',userName:$('#vUser').value.trim()||state.user.name};state.activeVisit=visit;save();closeModal();go({view:'visit'})}}
function persist(v){state.activeVisit=v;visit=v;save()}
function quickOk(iid){const v=visit||state.activeVisit;setCheck(v.projectId,v.stageId,v.sector,iid,{status:'ok',note:'',dueDate:null,contactId:null,visitId:v.id});const old=state.issues.find(i=>i.projectId===v.projectId&&i.stageId===v.stageId&&i.sector===v.sector&&i.itemId===iid&&i.lifecycle!=='Verificada');if(old)old.lifecycle='Verificada';save();render();toast('Marcado conforme')}
function checkModal(iid){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId),it=s.items.find(x=>x.id===iid),c=getCheck(p.id,s.id,v.sector,iid);detail={v,p,s,it,c};modal(it.task,`<div class="check-meta" style="margin-bottom:11px">${it.priority==='Crítica'?'<span class="pill red">Crítico</span>':''}${it.blocks?'<span class="pill">Bloquea avance</span>':''}</div><div class="future"><b>Previsión futura</b><br>${esc(it.future)}</div><div class="field"><label>Resultado</label><div class="segments"><button class="segment green ${c.status==='ok'?'sel':''}" data-status="ok">Conforme</button><button class="segment yellow ${c.status==='obs'?'sel':''}" data-status="obs">Observación</button><button class="segment red ${c.status==='bad'?'sel':''}" data-status="bad">No conforme</button></div></div><div class="field"><label>Comentario</label><textarea id="note" placeholder="Describir ubicación, carencia y acción requerida...">${esc(c.note||'')}</textarea><div class="actions"><button id="dictate">${ico('mic')} Dictar</button><button id="addPhoto">${ico('camera')} Fotos</button></div></div><div id="issueFields" style="${['obs','bad'].includes(c.status)?'':'display:none'}"><div class="inline"><div class="field"><label>Responsable</label><select id="contact"><option value="">Sin asignar</option>${p.contacts.map(x=>`<option value="${x.id}" ${x.id===c.contactId?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div class="field"><label>Fecha límite</label><input id="due" type="date" value="${esc(c.dueDate||'')}"></div></div>${lifeHtml(p.id,s.id,v.sector,iid)}</div><div class="field"><label>Fotografías</label><div class="photos" id="photos"></div></div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveCheck">Guardar</button>`);$$('[data-status]').forEach(b=>b.onclick=()=>{$$('[data-status]').forEach(x=>x.classList.remove('sel'));b.classList.add('sel');$('#issueFields').style.display=['obs','bad'].includes(b.dataset.status)?'block':'none'});$$('[data-life]').forEach(b=>b.onclick=()=>{$$('[data-life]').forEach(x=>x.classList.remove('sel'));b.classList.add('sel')});$('#dictate').onclick=dictate;$('#addPhoto').onclick=()=>{$('#photoInput').dataset.base=photoBase();$('#photoInput').click()};$('#saveCheck').onclick=saveCheckDetail;renderPhotos(photoBase())}
function lifeHtml(pid,sid,sector,iid){const x=state.issues.find(i=>i.projectId===pid&&i.stageId===sid&&i.sector===sector&&i.itemId===iid&&i.lifecycle!=='Verificada'),current=x?.lifecycle||'Abierta';return`<div class="field"><label>Estado de observación</label><div class="lifecycle">${FLOW.map(v=>`<button class="life ${v===current?'sel':''}" data-life="${v}">${v}</button>`).join('')}</div></div>`}
function photoBase(){const{v,it}=detail;return`${v.projectId}|${v.stageId}|${v.sector}|${it.id}`}
function saveCheckDetail(){const{v,p,s,it}=detail,sel=$('[data-status].sel'),current=getCheck(p.id,s.id,v.sector,it.id);const status=sel?.dataset.status||current.status||'pending',note=$('#note').value.trim(),due=$('#due')?.value||null,contactId=$('#contact')?.value||null;setCheck(p.id,s.id,v.sector,it.id,{status,note,dueDate:due,contactId,visitId:v.id});const old=state.issues.find(i=>i.projectId===p.id&&i.stageId===s.id&&i.sector===v.sector&&i.itemId===it.id&&i.lifecycle!=='Verificada');if(['obs','bad'].includes(status)){const contact=p.contacts.find(x=>x.id===contactId),payload={id:old?.id||crypto.randomUUID(),code:old?.code||nextCode(p.id),projectId:p.id,stageId:s.id,sector:v.sector,itemId:it.id,title:it.task,status,priority:it.priority,note,dueDate:due,contactId,contactName:contact?.name||'',lifecycle:$('[data-life].sel')?.dataset.life||old?.lifecycle||'Abierta',createdAt:old?.createdAt||new Date().toISOString(),updatedAt:new Date().toISOString(),visitId:v.id};if(old)Object.assign(old,payload);else state.issues.push(payload)}else if(old)old.lifecycle='Verificada';save();closeModal();render();toast('Control guardado')}
function nextCode(pid){return`OBS-${String(state.issues.filter(i=>i.projectId===pid).length+1).padStart(4,'0')}`}
function dictate(){const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR)return toast('El navegador no admite dictado');const r=new SR();r.lang='es-UY';r.onstart=()=>toast('Escuchando…');r.onresult=e=>$('#note').value=($('#note').value+' '+e.results[0][0].transcript).trim();r.onerror=()=>toast('No se pudo usar el micrófono');r.start()}
function leaveVisit(){const v=visit||state.activeVisit;save();go({view:'project',projectId:v.projectId})}
function saveVisitSnapshot(closeVisit=false){const v=visit||state.activeVisit,p=project(v.projectId),s=stage(v.stageId);let reviewed=0,issues=0,ok=0;for(const it of s.items){const c=getCheck(p.id,s.id,v.sector,it.id);if(c.status!=='pending')reviewed++;if(c.status==='ok')ok++;if(['obs','bad'].includes(c.status))issues++}const stored={...v,endedAt:closeVisit?new Date().toISOString():null,reviewed,issues,ok,userName:v.userName||state.user.name};const n=state.visits.findIndex(x=>x.id===v.id);if(n>=0)state.visits[n]=stored;else state.visits.push(stored);p.currentStage=s.id;if(closeVisit&&v.plannedVisitId){const planned=state.plannedVisits.find(x=>x.id===v.plannedVisitId);if(planned)planned.status='completed'}save();return stored}
function saveAndReturn(){const v=visit||state.activeVisit,stored=saveVisitSnapshot(true);state.activeVisit=null;visit=null;save();go({view:'project',projectId:stored.projectId});toast('Visita guardada')}
function exportVisitPdf(){const stored=saveVisitSnapshot(false);reportModal(stored.id)}
function finishVisit(){saveAndReturn()}
function reportModal(id){const v=state.visits.find(x=>x.id===id);if(!v)return;modal('Informe de visita',report(v),`<button class="ghost" data-close>Cerrar</button><button class="ghost" id="share">${ico('share')} Compartir</button><button class="solid" id="print">${ico('download')} Guardar PDF</button>`);$('#print').onclick=()=>print();$('#share').onclick=async()=>{const t=`Informe de visita · ${project(v.projectId).name} · ${stage(v.stageId).name} · ${fmt(v.startedAt,true)}`;if(navigator.share)await navigator.share({title:'Informe de visita',text:t});else{await navigator.clipboard.writeText(t);toast('Resumen copiado')}}}
function report(v){const p=project(v.projectId),s=stage(v.stageId),iss=state.issues.filter(i=>i.visitId===v.id),rows=s.items.map(it=>{const c=getCheck(p.id,s.id,v.sector,it.id);return`<tr><td>${it.id}</td><td>${esc(it.task)}</td><td>${label(c.status)}</td><td>${esc(c.note||'')}</td></tr>`}).join('');return`<div class="report"><h1>JP · Informe de visita</h1><div class="report-meta"><b>Proyecto:</b> ${esc(p.name)}<br><b>Etapa:</b> ${esc(s.name)}<br><b>Sector:</b> ${esc(v.sector)}<br><b>Fecha:</b> ${fmt(v.startedAt,true)}<br><b>Arquitecto:</b> ${esc(v.userName||state.user.name)}</div><h2>Resumen</h2><div class="report-meta">${v.reviewed} controles revisados · ${v.ok} conformes · ${v.issues} observaciones/no conformidades</div><h2>Controles</h2><table><thead><tr><th>ID</th><th>Control</th><th>Estado</th><th>Comentario</th></tr></thead><tbody>${rows}</tbody></table><h2>Observaciones</h2>${iss.map(i=>`<div class="report-obs"><b>${esc(i.code)} · ${esc(i.title)}</b><p>${esc(i.note)}</p><p>Responsable: ${esc(i.contactName||'Sin asignar')} · Vence: ${i.dueDate?fmt(i.dueDate):'Sin fecha'} · Estado: ${esc(i.lifecycle)}</p></div>`).join('')||'<p>Sin observaciones.</p>'}<div style="margin-top:45px;border-top:1px solid #999;padding-top:7px;font-size:10px">Dirección de obra · JP</div></div>`}
function label(s){return({pending:'Sin revisar',ok:'Conforme',obs:'Con observación',bad:'No conforme'})[s]||s}
function issueModal(id){const i=state.issues.find(x=>x.id===id);if(!i)return;modal(`${i.code} · ${i.title}`,`<div class="check-meta"><span class="pill ${i.status==='bad'?'red':'yellow'}">${i.status==='bad'?'No conforme':'Observación'}</span><span class="pill">${esc(i.priority)}</span></div><p style="line-height:1.5">${esc(i.note)}</p><div class="inline"><div class="field"><label>Responsable</label><input value="${esc(i.contactName||'Sin asignar')}" disabled></div><div class="field"><label>Fecha límite</label><input value="${esc(i.dueDate||'')}" disabled></div></div><div class="field"><label>Estado</label><div class="lifecycle">${FLOW.map(x=>`<button class="life ${x===i.lifecycle?'sel':''}" data-issue-life="${x}">${x}</button>`).join('')}</div></div>`,`<button class="ghost" data-close>Cerrar</button><button class="solid" id="saveLife">Guardar estado</button>`);$$('[data-issue-life]').forEach(b=>b.onclick=()=>{$$('[data-issue-life]').forEach(x=>x.classList.remove('sel'));b.classList.add('sel')});$('#saveLife').onclick=()=>{i.lifecycle=$('[data-issue-life].sel').dataset.issueLife;i.updatedAt=new Date().toISOString();save();closeModal();render();toast('Estado actualizado')}}
function issuesModal(pid){modal('Observaciones abiertas',`<div class="list">${openIssues(pid).map(issueRow).join('')||empty('No hay observaciones abiertas.')}</div>`,`<button class="solid" data-close>Cerrar</button>`);$$('[data-issue]',$('#modal')).forEach(b=>b.onclick=()=>{closeModal();issueModal(b.dataset.issue)})}
function newProject(){modal('Nuevo proyecto',`<div class="field"><label>Nombre</label><input id="npName" placeholder="Ej.: Vivienda Carrasco"></div><div class="field"><label>Plantilla de sectores</label><select id="npTemplate">${Object.keys(templates).map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="inline"><div class="field"><label>Cliente</label><input id="npClient"></div><div class="field"><label>Ubicación</label><input id="npLocation"></div></div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="createProject">Crear</button>`);$('#createProject').onclick=async()=>{const name=$('#npName').value.trim();if(!name)return toast('Ingresá un nombre');const button=$('#createProject'),template=$('#npTemplate').value;button.disabled=true;button.textContent='Creando…';try{const{data:id,error}=await sb.rpc('create_project_bundle',{p_name:name,p_client:$('#npClient').value.trim(),p_location:$('#npLocation').value.trim(),p_template:template,p_status:'En ejecución',p_current_stage:'preobra',p_enabled_stages:stages.map(s=>s.id),p_sector_names:templates[template]});if(error)throw error;await loadRemoteWorkspace();closeModal();go({view:'project',projectId:id});toast('Proyecto creado y sincronizado')}catch(error){button.disabled=false;button.textContent='Crear';toast(dbErrorText(error))}}}
function projectMenu(p){openProjectAdmin(p)}
async function syncProjectSectors(p,names){const current=p.sectorRecords||[],keepIds=[];for(let n=0;n<names.length;n++){const name=names[n],old=current.find(x=>x.name===name);if(old){keepIds.push(old.id);const{error}=await sb.from('project_sectors').update({sort_order:n}).eq('id',old.id);if(error)throw error}else{const{data,error}=await sb.from('project_sectors').insert({project_id:p.id,name,sort_order:n}).select().single();if(error)throw error;keepIds.push(data.id)}}const remove=current.filter(x=>!keepIds.includes(x.id)).map(x=>x.id);if(remove.length){const{error}=await sb.from('project_sectors').delete().in('id',remove);if(error)throw error}}
async function syncProjectContacts(p,names){const current=p.contacts||[],keepIds=[];for(const name of names){const old=current.find(x=>x.name===name);if(old)keepIds.push(old.id);else{const{data,error}=await sb.from('contacts').insert({project_id:p.id,name}).select().single();if(error)throw error;keepIds.push(data.id)}}const remove=current.filter(x=>!keepIds.includes(x.id)).map(x=>x.id);if(remove.length){const{error}=await sb.from('contacts').delete().in('id',remove);if(error)throw error}}
function stageConfig(p){modal('Etapas habilitadas',`<div class="list">${stages.map(s=>`<label class="row"><input type="checkbox" value="${s.id}" ${p.enabledStages.includes(s.id)?'checked':''}><div class="row-main"><div class="row-title">${esc(s.name)}</div></div></label>`).join('')}</div><div class="section"><button class="ghost" id="custom">${ico('plus')} Agregar control propio</button></div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveStages">Guardar</button>`);$('#saveStages').onclick=async()=>{const button=$('#saveStages'),enabledStages=$$('input[type=checkbox]:checked').map(x=>x.value);button.disabled=true;button.textContent='Guardando…';const{error}=await sb.from('projects').update({enabled_stages:enabledStages,updated_at:new Date().toISOString()}).eq('id',p.id);if(error){button.disabled=false;button.textContent='Guardar';return toast(dbErrorText(error))}p.enabledStages=enabledStages;save();closeModal();render();toast('Etapas sincronizadas')};$('#custom').onclick=()=>{closeModal();customControl()}}
function customControl(){modal('Nuevo control',`<div class="field"><label>Etapa</label><select id="ccStage">${stages.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select></div><div class="field"><label>Texto del control</label><input id="ccText"></div><div class="field"><label>Previsión futura</label><textarea id="ccFuture"></textarea></div><div class="inline"><div class="field"><label>Prioridad</label><select id="ccPriority"><option>Media</option><option>Alta</option><option>Crítica</option></select></div><div class="field"><label>Bloquea avance</label><select id="ccBlock"><option value="false">No</option><option value="true">Sí</option></select></div></div>`,`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveCustom">Agregar</button>`);$('#saveCustom').onclick=()=>{const s=stage($('#ccStage').value),task=$('#ccText').value.trim();if(!task)return toast('Ingresá el control');s.items.push({id:`CUS-${Date.now()}`,rubro:'Personalizado',task,future:$('#ccFuture').value.trim(),priority:$('#ccPriority').value,blocks:$('#ccBlock').value==='true'});closeModal();toast('Control agregado en esta sesión')}}
function search(q){q=q.trim().toLowerCase();const r=$('#searchResults');if(!q){r.innerHTML=empty('Ingresá un término de búsqueda.');return}const iss=state.issues.filter(i=>[i.code,i.title,i.note,i.contactName,i.sector].join(' ').toLowerCase().includes(q)),ps=state.projects.filter(p=>[p.name,p.client,p.location,p.status].join(' ').toLowerCase().includes(q)),cs=[];for(const p of state.projects)for(const s of stages)for(const it of s.items)if([it.task,it.future,s.name].join(' ').toLowerCase().includes(q))cs.push({p,s,it});r.innerHTML=[...ps.map(projectRow),...iss.map(issueRow),...cs.slice(0,20).map(x=>`<button class="row" data-project="${x.p.id}"><span class="dot"></span><div class="row-main"><div class="row-title">${esc(x.it.task)}</div><div class="row-sub">${esc(x.p.name)} · ${esc(x.s.name)}</div></div>${ico('next')}</button>`)].join('')||empty('No se encontraron resultados.');$$('[data-project]',r).forEach(b=>b.onclick=()=>go({view:'project',projectId:b.dataset.project}));$$('[data-issue]',r).forEach(b=>b.onclick=()=>issueModal(b.dataset.issue))}
function modal(title,body,foot=''){$('#modal').innerHTML=`<div class="modal-bg"><section class="modal-card"><div class="modal-head"><h2>${esc(title)}</h2><button class="icon-btn" data-close>×</button></div><div class="modal-body">${body}</div><div class="modal-foot">${foot}</div></section></div>`;$$('[data-close]',$('#modal')).forEach(b=>b.onclick=closeModal);$('.modal-bg').onclick=e=>{if(e.target.classList.contains('modal-bg'))closeModal()}}
function closeModal(){$('#modal').innerHTML=''}
$('#bottomNav').onclick=e=>{const b=e.target.closest('button');if(b)go({view:b.dataset.nav})};$('#brandBtn').onclick=()=>go({view:'home'});$('#settingsBtn').onclick=settings;
function settings(){modal('Configuración',`<div class="field"><label>Usuario</label><input value="${esc(currentProfile?.full_name||state.user.name||currentSession.user.email)}" disabled></div><div class="field"><label>Correo</label><input value="${esc(currentSession.user.email||'')}" disabled></div><div class="list"><button class="row" id="syncSettings">${ico('download')}<div class="row-main"><div class="row-title">Actualizar desde Supabase</div><div class="row-sub">Última sincronización: ${lastSync?fmt(lastSync,true):'Sin sincronizar'}</div></div></button><button class="row" id="export">${ico('download')}<div class="row-main"><div class="row-title">Exportar copia local</div><div class="row-sub">Visitas, checks, observaciones y caché de proyectos</div></div></button><button class="row" id="import">${ico('file')}<div class="row-main"><div class="row-title">Importar copia local</div><div class="row-sub">No reemplaza los proyectos almacenados en Supabase</div></div></button></div><input id="backup" type="file" accept=".json" hidden><p class="muted" style="margin-top:13px">v8 sincroniza usuarios, proyectos, sectores, contactos y accesos del equipo. El resto permanece local durante la prueba.</p>`,`<button class="danger" id="logout">Cerrar sesión</button><button class="solid" data-close>Cerrar</button>`);$('#syncSettings').onclick=async()=>{await refreshRemote();closeModal()};$('#logout').onclick=async()=>{closeModal();await sb.auth.signOut()};$('#export').onclick=()=>download(`jp-control-${Date.now()}.json`,JSON.stringify(state,null,2),'application/json');$('#import').onclick=()=>$('#backup').click();$('#backup').onchange=async e=>{try{const d=JSON.parse(await e.target.files[0].text());if(!d.checks)throw 0;const remoteProjects=state.projects;state={...d,projects:remoteProjects,user:state.user};save();closeModal();render();toast('Datos locales restaurados')}catch(err){toast('Archivo no válido')}}}
function download(name,text,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}

async function initAuth(){try{const{data:{session},error}=await sb.auth.getSession();if(error)throw error;currentSession=session;if(session)await loadRemoteWorkspace()}catch(error){authMessage=dbErrorText(error);workspaceError=authMessage}finally{authReady=true;render()}sb.auth.onAuthStateChange((event,session)=>{currentSession=session;if(event==='SIGNED_OUT'){currentProfile=null;state.projects=[];workspaceError='';save();route={view:'home'};setTimeout(()=>render(),0)}else if(session&&(event==='SIGNED_IN'||event==='TOKEN_REFRESHED'||event==='INITIAL_SESSION'))setTimeout(async()=>{try{await loadRemoteWorkspace()}catch(error){workspaceError=dbErrorText(error)}authReady=true;render()},0)})}
async function refreshRemote(){if(syncing)return;syncing=true;render();try{await loadRemoteWorkspace();toast('Datos actualizados')}catch(error){workspaceError=dbErrorText(error);toast(workspaceError)}finally{syncing=false;render()}}
async function loadRemoteWorkspace(){if(!currentSession)return;syncing=true;const uid=currentSession.user.id;const{data:profileData,error:profileError}=await sb.from('profiles').select('id,full_name,app_role').eq('id',uid).maybeSingle();if(profileError)throw profileError;if(!profileData)throw new Error('No existe el perfil del usuario. Revisá el trigger handle_new_user en Supabase.');currentProfile=profileData;state.user={id:uid,name:profileData.full_name||currentSession.user.email,role:profileData.app_role};const{data:rows,error}=await sb.rpc('get_my_projects');if(error)throw error;state.projects=(rows||[]).map(r=>({id:r.project_id,name:r.project_name,client:r.client||'',location:r.location||'',template:r.template||'Vivienda',status:r.project_status||'En ejecución',currentStage:r.current_stage||'preobra',enabledStages:Array.isArray(r.enabled_stages)&&r.enabled_stages.length?r.enabled_stages:stages.map(s=>s.id),projectRole:r.member_role||'read_only',sectors:Array.isArray(r.sectors)&&r.sectors.length?r.sectors.map(s=>s.name):['General'],sectorRecords:Array.isArray(r.sectors)?r.sectors:[],contacts:Array.isArray(r.contacts)?r.contacts.map(c=>({id:c.id,name:c.name,trade:c.trade||'',phone:c.phone||'',email:c.email||''})):[],members:project(r.project_id)?.members||[],createdAt:r.created_at}));if(state.activeVisit&&!state.projects.some(p=>p.id===state.activeVisit.projectId)){state.activeVisit=null;visit=null}lastSync=new Date().toISOString();workspaceError='';syncing=false;save()}
function dbErrorText(error){const message=error?.message||String(error||'Error desconocido'),m=message.toLowerCase();if(m.includes('function public.get_my_projects')||m.includes('could not find the function')||m.includes('create_project_bundle'))return'Falta ejecutar la migración v2 de Supabase antes de usar esta versión.';if(m.includes('row-level security'))return'La política RLS bloqueó esta operación. Revisá la membresía del proyecto.';if(m.includes('no existe un usuario')||m.includes('user_not_found'))return'No existe un usuario de Supabase con ese correo. Crealo primero en Authentication → Users.';if(m.includes('duplicate key'))return'Ya existe un registro con esos datos.';if(m.includes('failed to fetch'))return'No se pudo conectar con Supabase. Revisá internet y la URL del proyecto.';return message}

let dbp=new Promise((res,rej)=>{const r=indexedDB.open(PHOTO_DB,1);r.onupgradeneeded=()=>r.result.createObjectStore('photos',{keyPath:'id'});r.onsuccess=()=>res(r.result);r.onerror=()=>rej(r.error)});
async function photos(base){const db=await dbp;return new Promise((res,rej)=>{const r=db.transaction('photos').objectStore('photos').getAll();r.onsuccess=()=>res(r.result.filter(x=>x.base===base));r.onerror=()=>rej(r.error)})}
async function putPhoto(o){const db=await dbp;return new Promise((res,rej)=>{const tx=db.transaction('photos','readwrite');tx.objectStore('photos').put(o);tx.oncomplete=res;tx.onerror=()=>rej(tx.error)})}
async function delPhoto(id){const db=await dbp;db.transaction('photos','readwrite').objectStore('photos').delete(id)}
async function renderPhotos(base){const list=await photos(base),r=$('#photos');if(!r)return;r.innerHTML=list.map(p=>`<div class="photo"><img src="${p.data}" data-photo="${p.id}"><button data-del="${p.id}">×</button></div>`).join('');$$('[data-del]',r).forEach(b=>b.onclick=async()=>{await delPhoto(b.dataset.del);renderPhotos(base)});$$('[data-photo]',r).forEach(i=>i.onclick=()=>annotate(i.dataset.photo))}
$('#photoInput').onchange=async e=>{const base=e.target.dataset.base;if(!base)return;for(const f of e.target.files)await putPhoto({id:crypto.randomUUID(),base,data:await compress(f),createdAt:new Date().toISOString()});e.target.value='';renderPhotos(base);toast('Fotografías agregadas')}
function compress(file){return new Promise((res,rej)=>{const img=new Image(),url=URL.createObjectURL(file);img.onload=()=>{let w=img.width,h=img.height,max=1400;if(w>h&&w>max){h*=max/w;w=max}else if(h>max){w*=max/h;h=max}const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(img,0,0,w,h);URL.revokeObjectURL(url);res(c.toDataURL('image/jpeg',.76))};img.onerror=rej;img.src=url})}
async function annotate(id){const db=await dbp,photo=await new Promise((res,rej)=>{const r=db.transaction('photos').objectStore('photos').get(id);r.onsuccess=()=>res(r.result);r.onerror=()=>rej(r.error)});modal('Marcar fotografía','<div class="annot"><canvas id="canvas"></canvas></div><div class="annot-tools"><button id="draw">Dibujo libre</button><button id="text">Agregar texto</button><button id="restore">Restaurar</button></div>',`<button class="ghost" data-close>Cancelar</button><button class="solid" id="saveAnnot">Guardar</button>`);const c=$('#canvas'),ctx=c.getContext('2d'),img=new Image();let mode='draw',drawing=false,base=photo.data;img.onload=()=>{c.width=img.width;c.height=img.height;ctx.drawImage(img,0,0)};img.src=photo.data;const pos=e=>{const r=c.getBoundingClientRect();return{x:(e.clientX-r.left)*c.width/r.width,y:(e.clientY-r.top)*c.height/r.height}};c.onpointerdown=e=>{if(mode==='text'){const t=prompt('Texto a agregar');if(t){const p=pos(e);ctx.font=`${Math.max(24,c.width/30)}px Arial`;ctx.fillStyle='#fff';ctx.strokeStyle='#000';ctx.lineWidth=4;ctx.strokeText(t,p.x,p.y);ctx.fillText(t,p.x,p.y)}return}drawing=true;const p=pos(e);ctx.beginPath();ctx.moveTo(p.x,p.y)};c.onpointermove=e=>{if(!drawing||mode!=='draw')return;const p=pos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#ff3b30';ctx.lineWidth=Math.max(5,c.width/180);ctx.lineCap='round';ctx.stroke()};c.onpointerup=()=>drawing=false;$('#draw').onclick=()=>mode='draw';$('#text').onclick=()=>{mode='text';toast('Tocá la foto donde irá el texto')};$('#restore').onclick=()=>{const x=new Image();x.onload=()=>{ctx.clearRect(0,0,c.width,c.height);ctx.drawImage(x,0,0)};x.src=base};$('#saveAnnot').onclick=async()=>{photo.data=c.toDataURL('image/jpeg',.82);await putPhoto(photo);closeModal();renderPhotos(photo.base);toast('Marcación guardada')}}
initAuth();